class Solution {
public:
    int distinctSequences(int n) {
        const int MOD = 1e9 + 7;
        vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(6, vector<int>(6, -1)));
        auto dfs = [&](auto&& self, int i, int prev, int pprev) -> int {
            if (i == n) return 1;
            if (dp[i][prev][pprev] != -1) return dp[i][prev][pprev];
            int res = 0;
            for (int j = 0; j < 6; ++j) {
                if (gcd(prev + 1, j + 1) != 1) continue;
                if (j == pprev) continue;
                res = (res + self(self, i + 1, j, prev)) % MOD;
            }
            return dp[i][prev][pprev] = res;
        };
        int res = 0;
        for (int i = 0; i < 6; ++i) {
            res = (res + dfs(dfs, 1, i, -1)) % MOD;
        }
        return res;
    }
};
